namespace UniversityCourseCatalog.Models;

public class Department
{
    public int Id { get; set; }
    public string Name { get; set; } = string.Empty;
    public string Code { get; set; } = string.Empty;
    public string Description { get; set; } = string.Empty;
}

namespace UniversityCourseCatalog.Models;

public class Course
{
    public int Id { get; set; }
    public string Title { get; set; } = string.Empty;
    public string CourseCode { get; set; } = string.Empty;
    public string Description { get; set; } = string.Empty;
    public int Credits { get; set; }
    public string Schedule { get; set; } = string.Empty;
    public string InstructorName { get; set; } = string.Empty;
    public string InstructorBio { get; set; } = string.Empty;
    public int DepartmentId { get; set; }
    public string DepartmentName { get; set; } = string.Empty;
    public bool IsFeatured { get; set; }
}

using System.ComponentModel.DataAnnotations;

namespace UniversityCourseCatalog.Models;

public class EnrollmentRequest
{
    [Required(ErrorMessage = "Name is required.")]
    [StringLength(100)]
    public string StudentName { get; set; } = string.Empty;

    [Required(ErrorMessage = "Student ID is required.")]
    [RegularExpression(@"^[A-Za-z0-9\-]+$", ErrorMessage = "Student ID must contain only letters, numbers, and hyphens.")]
    public string StudentId { get; set; } = string.Empty;

    [Required(ErrorMessage = "Please select a course.")]
    [Range(1, int.MaxValue, ErrorMessage = "Please select a course.")]
    public int CourseId { get; set; }
}

using UniversityCourseCatalog.Models;

namespace UniversityCourseCatalog.Services;

public interface ICatalogService
{
    IReadOnlyList<Department> GetDepartments();
    Department? GetDepartment(int id);
    IReadOnlyList<Course> GetCourses(string? searchTerm = null, int? departmentId = null);
    IReadOnlyList<Course> GetFeaturedCourses();
    Course? GetCourse(int id);
    bool SubmitEnrollment(EnrollmentRequest request);
}

using UniversityCourseCatalog.Models;

namespace UniversityCourseCatalog.Services;

public class CatalogService : ICatalogService
{
    private readonly List<Department> _departments;
    private readonly List<Course> _courses;

    public CatalogService()
    {
        _departments = new List<Department>
        {
            new() { Id = 1, Name = "Computer Science", Code = "CS", Description = "Study of computation, algorithms, and information systems." },
            new() { Id = 2, Name = "Mathematics", Code = "MATH", Description = "Pure and applied mathematics including statistics and analysis." },
            new() { Id = 3, Name = "Physics", Code = "PHYS", Description = "Fundamental laws of nature, from quantum mechanics to cosmology." },
            new() { Id = 4, Name = "English", Code = "ENG", Description = "Literature, writing, and linguistic analysis." },
            new() { Id = 5, Name = "History", Code = "HIST", Description = "Study of past events and their impact on modern society." },
        };

        _courses = new List<Course>
        {
            new() { Id = 1, Title = "Introduction to Programming", CourseCode = "CS 101", Description = "Fundamentals of programming using Python. Covers variables, control flow, functions, and basic data structures. No prior experience required.", Credits = 3, Schedule = "Mon/Wed/Fri 9:00–9:50 AM", InstructorName = "Dr. Sarah Chen", InstructorBio = "Dr. Chen has 15 years of experience teaching introductory CS courses and is the author of 'Python for Everyone'.", DepartmentId = 1, DepartmentName = "Computer Science", IsFeatured = true },
            new() { Id = 2, Title = "Data Structures and Algorithms", CourseCode = "CS 201", Description = "In-depth study of arrays, linked lists, trees, graphs, sorting, and searching algorithms. Emphasis on time and space complexity analysis.", Credits = 4, Schedule = "Tue/Thu 10:30–11:50 AM", InstructorName = "Dr. James Rodriguez", InstructorBio = "Dr. Rodriguez specializes in algorithm design and has published over 40 papers in top venues.", DepartmentId = 1, DepartmentName = "Computer Science", IsFeatured = true },
            new() { Id = 3, Title = "Database Systems", CourseCode = "CS 310", Description = "Relational database design, SQL, normalization, transaction processing, and introduction to NoSQL databases.", Credits = 3, Schedule = "Mon/Wed 2:00–3:20 PM", InstructorName = "Prof. Maria Gonzalez", InstructorBio = "Prof. Gonzalez worked as a database architect at a Fortune 500 company before joining academia.", DepartmentId = 1, DepartmentName = "Computer Science", IsFeatured = false },
            new() { Id = 4, Title = "Calculus I", CourseCode = "MATH 151", Description = "Limits, derivatives, and integrals of single-variable functions. Applications to physics and engineering.", Credits = 4, Schedule = "Mon/Wed/Fri 10:00–10:50 AM", InstructorName = "Dr. Robert Kim", InstructorBio = "Dr. Kim is a recipient of the Distinguished Teaching Award and has taught calculus for over 20 years.", DepartmentId = 2, DepartmentName = "Mathematics", IsFeatured = true },
            new() { Id = 5, Title = "Linear Algebra", CourseCode = "MATH 220", Description = "Vectors, matrices, linear transformations, eigenvalues, and applications to data science and machine learning.", Credits = 3, Schedule = "Tue/Thu 1:00–2:20 PM", InstructorName = "Dr. Emily Park", InstructorBio = "Dr. Park's research focuses on computational linear algebra and its applications in AI.", DepartmentId = 2, DepartmentName = "Mathematics", IsFeatured = false },
            new() { Id = 6, Title = "Statistics and Probability", CourseCode = "MATH 301", Description = "Probability theory, random variables, distributions, hypothesis testing, and regression analysis.", Credits = 3, Schedule = "Mon/Wed 11:00 AM–12:20 PM", InstructorName = "Dr. Alan Foster", InstructorBio = "Dr. Foster is a biostatistician with extensive industry consulting experience.", DepartmentId = 2, DepartmentName = "Mathematics", IsFeatured = false },
            new() { Id = 7, Title = "General Physics I", CourseCode = "PHYS 101", Description = "Mechanics, thermodynamics, and waves. Includes weekly lab sessions.", Credits = 4, Schedule = "Tue/Thu 9:00–10:20 AM + Lab Fri 1:00–3:00 PM", InstructorName = "Dr. Lisa Wang", InstructorBio = "Dr. Wang is an experimental physicist whose research has been featured in Nature and Science.", DepartmentId = 3, DepartmentName = "Physics", IsFeatured = true },
            new() { Id = 8, Title = "Quantum Mechanics", CourseCode = "PHYS 401", Description = "Wave functions, Schrödinger equation, quantum states, and applications to atomic and molecular physics.", Credits = 3, Schedule = "Mon/Wed/Fri 11:00–11:50 AM", InstructorName = "Dr. David Okafor", InstructorBio = "Dr. Okafor is a theoretical physicist specializing in quantum information science.", DepartmentId = 3, DepartmentName = "Physics", IsFeatured = false },
            new() { Id = 9, Title = "English Composition", CourseCode = "ENG 101", Description = "Develops skills in academic writing, argumentation, research methods, and critical reading.", Credits = 3, Schedule = "Mon/Wed/Fri 1:00–1:50 PM", InstructorName = "Prof. Catherine Bell", InstructorBio = "Prof. Bell is an award-winning essayist and writing instructor with a passion for helping students find their voice.", DepartmentId = 4, DepartmentName = "English", IsFeatured = false },
            new() { Id = 10, Title = "American Literature", CourseCode = "ENG 250", Description = "Survey of American literature from the colonial period to the present, with emphasis on major movements and authors.", Credits = 3, Schedule = "Tue/Thu 2:30–3:50 PM", InstructorName = "Dr. Michael Torres", InstructorBio = "Dr. Torres specializes in 20th-century American fiction and has published two books on the Harlem Renaissance.", DepartmentId = 4, DepartmentName = "English", IsFeatured = false },
            new() { Id = 11, Title = "World History to 1500", CourseCode = "HIST 101", Description = "Survey of world civilizations from prehistory through the late medieval period, covering political, social, and cultural developments.", Credits = 3, Schedule = "Tue/Thu 11:00 AM–12:20 PM", InstructorName = "Dr. Patricia Nguyen", InstructorBio = "Dr. Nguyen is an archaeologist and historian specializing in ancient Mediterranean civilizations.", DepartmentId = 5, DepartmentName = "History", IsFeatured = false },
            new() { Id = 12, Title = "Modern European History", CourseCode = "HIST 302", Description = "Europe from the French Revolution to the present. Examines revolutions, world wars, and the rise of the European Union.", Credits = 3, Schedule = "Mon/Wed 3:30–4:50 PM", InstructorName = "Dr. Thomas Schmidt", InstructorBio = "Dr. Schmidt is a specialist in 20th-century European political history and a Fulbright Scholar.", DepartmentId = 5, DepartmentName = "History", IsFeatured = false },
        };
    }

    public IReadOnlyList<Department> GetDepartments() => _departments;

    public Department? GetDepartment(int id) => _departments.FirstOrDefault(d => d.Id == id);

    public IReadOnlyList<Course> GetCourses(string? searchTerm = null, int? departmentId = null)
    {
        var query = _courses.AsEnumerable();

        if (departmentId.HasValue)
        {
            query = query.Where(c => c.DepartmentId == departmentId.Value);
        }

        if (!string.IsNullOrWhiteSpace(searchTerm))
        {
            var term = searchTerm.Trim();
            query = query.Where(c =>
                c.Title.Contains(term, StringComparison.OrdinalIgnoreCase) ||
                c.CourseCode.Contains(term, StringComparison.OrdinalIgnoreCase) ||
                c.InstructorName.Contains(term, StringComparison.OrdinalIgnoreCase) ||
                c.DepartmentName.Contains(term, StringComparison.OrdinalIgnoreCase));
        }

        return query.ToList();
    }

    public IReadOnlyList<Course> GetFeaturedCourses() => _courses.Where(c => c.IsFeatured).ToList();

    public Course? GetCourse(int id) => _courses.FirstOrDefault(c => c.Id == id);

    public bool SubmitEnrollment(EnrollmentRequest request)
    {
        // In a real application this would persist to a database.
        return GetCourse(request.CourseId) is not null;
    }
}

